  }
};

// Fonction pour formater l'heure de HHMM vers HH:MM
const formatHeure = (heure) => {
  if (!heure || heure === 'N/A') return 'N/A';
  const heureStr = String(heure).padStart(4, '0');
  return `${heureStr.substring(0, 2)}:${heureStr.substring(2, 4)}`;
};

// Fonction pour convertir HHMM en minutes depuis minuit
const heureEnMinutes = (heure) => {
  if (!heure || heure === 'N/A') return null;
  const heureStr = String(heure).padStart(4, '0');
  const heures = parseInt(heureStr.substring(0, 2));
  const minutes = parseInt(heureStr.substring(2, 4));
  return heures * 60 + minutes;
};

// Fonction pour convertir des minutes en format "Xh Ymin"
const minutesEnTexte = (minutes, langue) => {
  if (minutes === null || isNaN(minutes)) return 'N/A';

  const heures = Math.floor(minutes / 60);
  const mins = minutes % 60;

  switch(langue) {
    case 'fr':
      if (heures > 0 && mins > 0) return `${heures}h ${mins}min`;
      if (heures > 0) return `${heures}h`;
      return `${mins}min`;

    case 'en':
      if (heures > 0 && mins > 0) return `${heures}h ${mins}min`;
      if (heures > 0) return `${heures}h`;
      return `${mins}min`;

    case 'ar':
      if (heures > 0 && mins > 0) return `${heures}س ${mins}د`;
      if (heures > 0) return `${heures}س`;
      return `${mins}د`;

    default:
      return `${heures}h ${mins}min`;
  }
};

// Fonction pour calculer la durée entre deux heures
const calculerDuree = (heureDebut, heureFin) => {
  const debut = heureEnMinutes(heureDebut);
  const fin = heureEnMinutes(heureFin);

  if (debut === null || fin === null) return null;

  let duree = fin - debut;

  // Gérer le cas où on passe minuit (rare mais possible)
  if (duree < 0) {
    duree += 24 * 60;
  }

  return duree;
};

// Récupérer les données
const items = $input.all();
const results = [];

for (const item of items) {
  // Récupérer les données du webhook (depuis le premier nœud)
  const webhookData = $('Webhook').item.json;

  // Merger les données SQL et webhook
  const mergedData = {
    // Données SQL
    XSAL_0: item.json.XSAL_0,
    XNAMSAL_0: item.json.XNAMSAL_0,
    XPRENOM_0: item.json.XPRENOM_0,
    XEMAIL_0: item.json.XEMAIL_0,
    TIDCHAT_0: item.json.TIDCHAT_0,
    LAN_0: item.json.LAN_0,
    // Données webhook
    query: webhookData.query
  };

  // Déterminer la langue (par défaut français si non spécifiée ou invalide)
  let langue = (mergedData.LAN_0 || 'fr').toLowerCase();

  // Normaliser les codes de langue
  if (langue === 'fra' || langue === 'french') langue = 'fr';
  if (langue === 'eng' || langue === 'english') langue = 'en';
  if (langue === 'ara' || langue === 'arabic') langue = 'ar';

  // Vérifier que la langue existe dans les templates
  if (!templates[langue]) {
    langue = 'fr'; // Défaut en français
  }

  const template = templates[langue];

  // Calculer les heures de travail
  const dureeMatin = calculerDuree(
    mergedData.query?.H_Entree_Matin,
    mergedData.query?.H_Sortie_Matin
  );

  const dureeApresMidi = calculerDuree(
    mergedData.query?.H_Entree_Apres,
    mergedData.query?.H_Sortie_Apres
  );

  // Calculer le total
  let dureeTotal = null;
  if (dureeMatin !== null && dureeApresMidi !== null) {
    dureeTotal = dureeMatin + dureeApresMidi;
  } else if (dureeMatin !== null) {
    dureeTotal = dureeMatin;
  } else if (dureeApresMidi !== null) {
    dureeTotal = dureeApresMidi;
  }

  // Préparer les données pour le remplacement
  const replacements = {
    Salarie: mergedData.XSAL_0 || 'N/A',
    Nom: mergedData.XNAMSAL_0 || '',
    Prenom: mergedData.XPRENOM_0 || '',
    Date: mergedData.query?.Date || 'N/A',
    Fichpointage: mergedData.query?.Fichpointage || 'N/A',
    H_Entree_Matin: formatHeure(mergedData.query?.H_Entree_Matin),
    H_Sortie_Matin: formatHeure(mergedData.query?.H_Sortie_Matin),
    H_Entree_Apres: formatHeure(mergedData.query?.H_Entree_Apres),
    H_Sortie_Apres: formatHeure(mergedData.query?.H_Sortie_Apres),
    Heures_Matin: minutesEnTexte(dureeMatin, langue),
    Heures_Apres_Midi: minutesEnTexte(dureeApresMidi, langue),
    Heures_Total: minutesEnTexte(dureeTotal, langue)
  };

  // Fonction pour remplacer les variables dans les templates
  const replaceVars = (text) => {
    let result = text;
    for (const [key, value] of Object.entries(replacements)) {
      const regex = new RegExp(`\\{\\{ ${key} \\}\\}`, 'g');
      result = result.replace(regex, value);
    }
    return result;
  };

  // Créer le résultat
  results.push({
    json: {
      // Données originales
      XSAL_0: mergedData.XSAL_0,
      XNAMSAL_0: mergedData.XNAMSAL_0,
      XPRENOM_0: mergedData.XPRENOM_0,
      XEMAIL_0: mergedData.XEMAIL_0,
      TIDCHAT_0: mergedData.TIDCHAT_0,
      LAN_0: mergedData.LAN_0,
      query: mergedData.query,

      // Données générées
      langue: langue,
      email_subject: replaceVars(template.subject),
      email_body: replaceVars(template.body),
      telegram_message: replaceVars(template.telegram),
      has_email: !!(mergedData.XEMAIL_0),
      has_telegram: !!(mergedData.TIDCHAT_0),

      // Données de débogage et statistiques
      debug_replacements: replacements,
      heures_travail: {
        matin_minutes: dureeMatin,
        apres_midi_minutes: dureeApresMidi,
        total_minutes: dureeTotal,
        matin_texte: minutesEnTexte(dureeMatin, langue),
        apres_midi_texte: minutesEnTexte(dureeApresMidi, langue),
        total_texte: minutesEnTexte(dureeTotal, langue)
      }
    }
  });
}

return results;
